/* Reset & Base */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  min-height: 100vh;
  padding: 24px 16px 48px;
  color: #1a1a2e;
}

.container {
  max-width: 800px;
  margin: 0 auto;
}

/* Header */
header {
  text-align: center;
  padding: 32px 0 24px;
  color: #fff;
}
header h1 { font-size: 2.4rem; font-weight: 800; letter-spacing: -0.5px; }
header .subtitle { margin-top: 8px; font-size: 1.05rem; opacity: 0.85; }

/* Card */
.card {
  background: #fff;
  border-radius: 16px;
  padding: 28px 32px;
  margin-bottom: 24px;
  box-shadow: 0 8px 32px rgba(0,0,0,0.12);
}
.card h2 {
  font-size: 1.2rem;
  font-weight: 700;
  margin-bottom: 20px;
  color: #1a1a2e;
  border-bottom: 2px solid #f0f0f5;
  padding-bottom: 10px;
}

/* Form */
.form-group {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-bottom: 16px;
}
.form-group label {
  font-size: 0.875rem;
  font-weight: 600;
  color: #444;
}
.required { color: #e74c3c; }

.form-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}
@media (max-width: 540px) { .form-row { grid-template-columns: 1fr; } }

input[type="text"], select {
  width: 100%;
  padding: 10px 14px;
  border: 2px solid #e0e0e8;
  border-radius: 8px;
  font-size: 0.95rem;
  transition: border-color 0.2s, box-shadow 0.2s;
  background: #fafafa;
  color: #1a1a2e;
}
input[type="text"]:focus, select:focus {
  outline: none;
  border-color: #667eea;
  box-shadow: 0 0 0 3px rgba(102,126,234,0.15);
  background: #fff;
}

/* Buttons */
.btn {
  cursor: pointer;
  border: none;
  border-radius: 8px;
  font-size: 0.9rem;
  font-weight: 600;
  padding: 10px 20px;
  transition: transform 0.1s, box-shadow 0.2s, opacity 0.2s;
}
.btn:active { transform: scale(0.97); }
.btn-primary {
  background: linear-gradient(135deg, #667eea, #764ba2);
  color: #fff;
  padding: 12px 28px;
  font-size: 1rem;
  width: 100%;
  margin-top: 4px;
  box-shadow: 0 4px 15px rgba(102,126,234,0.4);
}
.btn-primary:hover { opacity: 0.92; box-shadow: 0 6px 20px rgba(102,126,234,0.5); }
.btn-secondary {
  background: #f0f0f8;
  color: #555;
}
.btn-secondary:hover { background: #e4e4f0; }
.btn-copy {
  background: #667eea;
  color: #fff;
  padding: 6px 14px;
  font-size: 0.82rem;
}
.btn-copy:hover { background: #5567d4; }
.btn-danger {
  background: #fff0f0;
  color: #e74c3c;
  padding: 5px 12px;
  font-size: 0.8rem;
  border: 1px solid #fcc;
}
.btn-danger:hover { background: #ffe0e0; }

/* Result box */
.result-box {
  margin-top: 20px;
  padding: 16px 20px;
  background: #f0fdf4;
  border: 1.5px solid #86efac;
  border-radius: 10px;
}
.result-label { font-size: 0.85rem; color: #15803d; font-weight: 600; margin-bottom: 8px; }
.result-url-row {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
}
.result-url-row a {
  font-size: 1.05rem;
  font-weight: 700;
  color: #2563eb;
  word-break: break-all;
  text-decoration: none;
  border-bottom: 2px solid #93c5fd;
}
.result-url-row a:hover { color: #1d4ed8; }
.copy-msg {
  font-size: 0.8rem;
  color: #15803d;
  font-weight: 600;
  margin-top: 4px;
  display: block;
}

/* Error box */
.error-box {
  margin-top: 16px;
  padding: 12px 16px;
  background: #fff0f0;
  border: 1.5px solid #fca5a5;
  border-radius: 10px;
  color: #b91c1c;
  font-size: 0.9rem;
  font-weight: 500;
}

/* URL List */
.list-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
  border-bottom: 2px solid #f0f0f5;
  padding-bottom: 10px;
}
.list-header h2 { margin-bottom: 0; border: none; padding: 0; }

.url-list { display: flex; flex-direction: column; gap: 12px; }

.url-item {
  background: #fafafa;
  border: 1.5px solid #e8e8f0;
  border-radius: 10px;
  padding: 14px 16px;
  transition: box-shadow 0.2s;
}
.url-item:hover { box-shadow: 0 2px 12px rgba(0,0,0,0.07); }

.url-item-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 8px;
  flex-wrap: wrap;
}

.url-short {
  font-weight: 700;
  font-size: 1rem;
  color: #667eea;
  text-decoration: none;
  border-bottom: 1.5px solid #c7d2fe;
}
.url-short:hover { color: #4f46e5; }

.url-meta {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
}
.badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 0.78rem;
  font-weight: 600;
}
.badge-clicks { background: #e0f2fe; color: #0369a1; }
.badge-expires { background: #fef9c3; color: #92400e; }
.badge-expired { background: #fee2e2; color: #991b1b; }

.url-original {
  margin-top: 6px;
  font-size: 0.83rem;
  color: #777;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  max-width: 100%;
}

.url-date { font-size: 0.78rem; color: #aaa; margin-top: 4px; }

.loading { color: #aaa; font-size: 0.9rem; text-align: center; padding: 20px 0; }
.empty { color: #bbb; font-size: 0.9rem; text-align: center; padding: 32px 0; }

.hidden { display: none !important; }

