  gap: 8px;
  flex-wrap: wrap;
}

.url-short {
  font-weight: 700;
  font-size: 1rem;
  color: #667eea;
  text-decoration: none;
  border-bottom: 1.5px solid #c7d2fe;
}
.url-short:hover { color: #4f46e5; }

.url-meta {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
}
.badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 10px;
  border-radius: 20px;
  font-size: 0.78rem;
  font-weight: 600;
}
.badge-clicks { background: #e0f2fe; color: #0369a1; }
.badge-expires { background: #fef9c3; color: #92400e; }
.badge-expired { background: #fee2e2; color: #991b1b; }

.url-original {
  margin-top: 6px;
  font-size: 0.83rem;
  color: #777;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  max-width: 100%;
}

.url-date { font-size: 0.78rem; color: #aaa; margin-top: 4px; }

.loading { color: #aaa; font-size: 0.9rem; text-align: center; padding: 20px 0; }
.empty { color: #bbb; font-size: 0.9rem; text-align: center; padding: 32px 0; }

.hidden { display: none !important; }

